import{_ as t,o as n,c as a,a2 as o}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Team Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/team-management.md","filePath":"en/guide/team-management.md","lastUpdated":null}'),i={name:"en/guide/team-management.md"};function r(s,e,l,d,c,h){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="team-management" tabindex="-1">Team Management <a class="header-anchor" href="#team-management" aria-label="Permalink to &quot;Team Management&quot;">​</a></h1><p>The <strong>Team</strong> section allows the organization owner and administrators to manage members, send invitations, and control access levels across the platform.</p><h2 id="user-roles" tabindex="-1">User Roles <a class="header-anchor" href="#user-roles" aria-label="Permalink to &quot;User Roles&quot;">​</a></h2><p>SREBot uses a four-level role model within each organization. The set of available actions depends on the assigned role.</p><table tabindex="0"><thead><tr><th>Role</th><th>Incidents</th><th>Billing</th><th>Bot Settings</th><th>Team Management</th></tr></thead><tbody><tr><td><strong>Owner</strong></td><td>✅ View</td><td>✅ Full access</td><td>✅ Full access</td><td>✅ Full access</td></tr><tr><td><strong>Admin</strong></td><td>✅ View</td><td>✅ Full access</td><td>✅ Full access</td><td>✅ Invite &amp; manage members</td></tr><tr><td><strong>Member</strong></td><td>✅ View</td><td>❌ No access</td><td>❌ No access</td><td>❌ No access</td></tr><tr><td><strong>Viewer</strong></td><td>✅ View</td><td>❌ No access</td><td>❌ No access</td><td>❌ No access</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">One organization, one owner</p><p>Every organization has exactly one <strong>Owner</strong>. The user who creates the organization automatically receives this role. The Owner cannot be removed or demoted — only replaced via <strong>ownership transfer</strong>.</p></div><h3 id="role-descriptions" tabindex="-1">Role Descriptions <a class="header-anchor" href="#role-descriptions" aria-label="Permalink to &quot;Role Descriptions&quot;">​</a></h3><p><strong>Owner</strong></p><p>The highest role in the organization. Only the Owner can:</p><ul><li>Transfer ownership to another member.</li><li>Promote members to Admin.</li><li>Remove Admins from the organization.</li></ul><p><strong>Admin</strong></p><p>Can manage the team: invite new members, change their roles (Member and Viewer only), and remove regular members. Cannot modify the role of or remove the Owner or other Admins.</p><p><strong>Member</strong></p><p>A full team member with access to incident analytics. No access to billing, bot configuration, or team management.</p><p><strong>Viewer</strong></p><p>Minimum access level. Can only view the incident list and incident details.</p><hr><h2 id="inviting-members" tabindex="-1">Inviting Members <a class="header-anchor" href="#inviting-members" aria-label="Permalink to &quot;Inviting Members&quot;">​</a></h2><p><strong>Owners</strong> and <strong>Admins</strong> can invite new users.</p><ol><li>Go to the <strong>Team</strong> section in the sidebar.</li><li>In the <strong>«Invite New Member»</strong> form, enter the email address and select a role.</li><li>Click <strong>«Send Invitation»</strong>.</li></ol><p>An invitation link will be sent to the specified email, valid for <strong>48 hours</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Choosing a role when inviting</p><p>You can invite a user as a <strong>Viewer</strong>, <strong>Member</strong>, or <strong>Admin</strong>. The <strong>Owner</strong> role cannot be assigned via invitation — it can only be transferred to an existing member.</p></div><h3 id="accepting-an-invitation" tabindex="-1">Accepting an Invitation <a class="header-anchor" href="#accepting-an-invitation" aria-label="Permalink to &quot;Accepting an Invitation&quot;">​</a></h3><p>The user follows the link from the email. What happens next depends on whether they are already registered in SREBot:</p><p><strong>New user</strong></p><p>An account creation form is displayed. The user must set a password (minimum 8 characters). After clicking the button, the user is automatically logged in and redirected to the dashboard.</p><p><strong>Existing user</strong></p><p>An identity confirmation form is displayed. The user must enter the password for their existing account. This requirement protects against unauthorized access in the event the invitation link is intercepted.</p><div class="warning custom-block"><p class="custom-block-title">Invitation link security</p><p>The link expires after 48 hours. Never share it in public places — anyone who obtains the link can accept the invitation. If the link has been compromised, revoke the invitation in the <strong>«Pending Invitations»</strong> section.</p></div><hr><h2 id="managing-members" tabindex="-1">Managing Members <a class="header-anchor" href="#managing-members" aria-label="Permalink to &quot;Managing Members&quot;">​</a></h2><p>All current members of the organization are listed in the <strong>«Active Members»</strong> table.</p><h3 id="changing-a-role" tabindex="-1">Changing a Role <a class="header-anchor" href="#changing-a-role" aria-label="Permalink to &quot;Changing a Role&quot;">​</a></h3><p>The Owner and Admins can change member roles via the dropdown in the <strong>Actions</strong> column.</p><p>Restrictions:</p><ul><li>An <strong>Admin</strong> cannot change the role of the <strong>Owner</strong> or another <strong>Admin</strong>.</li><li>An <strong>Admin</strong> cannot promote members to <strong>Admin</strong> — only the Owner can do this.</li><li>No one can change their own role.</li></ul><h3 id="removing-a-member" tabindex="-1">Removing a Member <a class="header-anchor" href="#removing-a-member" aria-label="Permalink to &quot;Removing a Member&quot;">​</a></h3><p>Click the trash icon in the row of the member you want to remove. You will be prompted to confirm the action.</p><p>Restrictions:</p><ul><li>The <strong>Owner</strong> cannot be removed from the organization.</li><li>An <strong>Admin</strong> cannot remove another <strong>Admin</strong>.</li><li>You cannot remove yourself from the organization.</li></ul><hr><h2 id="transferring-ownership" tabindex="-1">Transferring Ownership <a class="header-anchor" href="#transferring-ownership" aria-label="Permalink to &quot;Transferring Ownership&quot;">​</a></h2><p>If you are the <strong>Owner</strong> and want to hand over the organization to another member:</p><ol><li>Go to the <strong>Team</strong> section.</li><li>In the target member&#39;s row, select <strong>«Owner (Transfer)»</strong> from the role dropdown.</li><li>Confirm the action in the dialog box.</li></ol><div class="danger custom-block"><p class="custom-block-title">Warning: irreversible action</p><p>After transferring ownership, you are automatically demoted to <strong>Admin</strong>. The new Owner gains full control over the organization, including the right to transfer ownership again.</p></div><hr><h2 id="managing-invitations" tabindex="-1">Managing Invitations <a class="header-anchor" href="#managing-invitations" aria-label="Permalink to &quot;Managing Invitations&quot;">​</a></h2><p>The <strong>«Pending Invitations»</strong> block (visible to Owners and Admins only) shows all invitations that have been sent but not yet accepted.</p><ul><li>Each invitation displays: email, assigned role, and expiry date.</li><li>Click <strong>«Revoke»</strong> to cancel an invitation before it is accepted.</li><li>After 48 hours, an invitation automatically becomes invalid.</li></ul>',49)])])}const p=t(i,[["render",r]]);export{g as __pageData,p as default};
